#!/usr/bin/env node
// betti-wasm-emit.mjs — emit the benchmark fixtures as betti-wasm/1 artifact
// pairs into dist/betti-wasm/ via the RELEASE Betti emitter (monster/gnexec).
//
// Backs the `betti:wasm:emit` package script / nx target. Fails closed when
// no release emitter binary exists — build one with
// `cargo build --bin gnexec --release` in open-source/gnosis/polyglot.
import { execFileSync } from 'node:child_process';
import { existsSync, mkdirSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const packageRoot = resolve(here, '..');
const releaseDir = join(packageRoot, 'polyglot', 'target', 'release');
const outDir = join(packageRoot, 'dist', 'betti-wasm');

const binary = [
  process.env.GNOSIS_MONSTER_BIN,
  join(releaseDir, 'monster'),
  join(releaseDir, 'gnexec'),
].find((candidate) => candidate && existsSync(candidate));

if (!binary) {
  process.stderr.write(
    'betti:wasm:emit: no RELEASE emitter binary at ' +
      `${releaseDir}/{monster,gnexec} (or $GNOSIS_MONSTER_BIN). ` +
      'Build one with `cargo build --bin gnexec --release` in open-source/gnosis/polyglot.\n'
  );
  process.exit(1);
}

const fixtures = [
  { source: 'gnode/benchmarks/echo.ts', exportName: 'app', out: 'echo.wasm' },
  { source: 'gnode/benchmarks/fib.ts', exportName: 'app', out: 'fib.wasm' },
  {
    source: 'gnode/benchmarks/sum-squares.ts',
    exportName: 'main',
    out: 'sum-squares.wasm',
  },
];

mkdirSync(outDir, { recursive: true });

for (const fixture of fixtures) {
  const outPath = join(outDir, fixture.out);
  execFileSync(
    binary,
    [
      join(packageRoot, fixture.source),
      '--export',
      fixture.exportName,
      '--emit-wasm-out',
      outPath,
    ],
    { stdio: ['ignore', 'inherit', 'inherit'] }
  );
  process.stdout.write(`betti:wasm:emit: ${fixture.source} -> ${outPath}\n`);
}
